import React, { useState } from 'react';
import './contact.css';

const Contact = () => {
  const [formName, setFormName] = useState('');
  const [formEmail, setFormEmail] = useState('');
  const [formCompany, setFormCompany] = useState('');  // 기존 jobMajor -> company
  const [formPhone, setFormPhone] = useState('');      // 새로 추가한 phone
  const [formDetails, setFormDetails] = useState('');  // 기존 request -> details

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:4000/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: formName,
          email: formEmail,
          jobMajor: formCompany,  // 서버에서 기존 jobMajor 필드로 받도록 함
          phone: formPhone,       // 새로 추가
          request: formDetails,   // 서버에서 기존 request 필드로 받도록 함
        }),
      });
      if (!response.ok) {
        throw new Error('Failed to submit');
      }
      alert('Thank you for your request! We will reply as soon as possible.');
      // 폼 초기화
      setFormName('');
      setFormEmail('');
      setFormCompany('');
      setFormPhone('');
      setFormDetails('');
    } catch (err) {
      console.error(err);
      alert('Error submitting form.');
    }
  };

  return (
    <section className="contact-container">
      {/* 왼쪽 안내/주소 영역 */}
      <div className="contact-left">
        <h2 className="contact-title">CONTACT ME</h2>
        <h3 className="contact-subtitle">AFX에 대한 문의사항이 있으신가요?</h3>
        <p className="contact-desc">
        AFX에 대한 문의사항이 있으신가요? 아래의 양식을 작성해 주시면, 최대한 성실하고 빠르게 답변 드리겠습니다.
        </p>

        <div className="contact-info-block">
          <h4>My Email</h4>
          <p>him21176@gmail.com</p>
        </div>
      </div>

      {/* 오른쪽 폼 영역 */}
      <div className="contact-right">
        <form onSubmit={handleSubmit} className="contact-form">
          {/* Name */}
          <div className="contact-form-group">
            <label htmlFor="name">Name</label>
            <input
              type="text"
              id="name"
              name="name"
              value={formName}
              onChange={(e) => setFormName(e.target.value)}
              required
            />
          </div>

          {/* Company Name */}
          <div className="contact-form-group">
            <label htmlFor="company">Purpose for AFX</label>
            <input
              type="text"
              id="company"
              name="company"
              value={formCompany}
              onChange={(e) => setFormCompany(e.target.value)}
              required
            />
          </div>

          {/* Email */}
          <div className="contact-form-group">
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              name="email"
              value={formEmail}
              onChange={(e) => setFormEmail(e.target.value)}
              required
            />
          </div>

          {/* Phone */}
          <div className="contact-form-group">
            <label htmlFor="phone">Phone Number</label>
            <input
              type="text"
              id="phone"
              name="phone"
              value={formPhone}
              onChange={(e) => setFormPhone(e.target.value)}
              required
            />
          </div>

          {/* Details */}
          <div className="contact-form-group contact-form-details">
            <label htmlFor="details">Detail Requirements</label>
            <textarea
              id="details"
              name="details"
              rows="5"
              value={formDetails}
              onChange={(e) => setFormDetails(e.target.value)}
              required
            />
          </div>

          <div className="contact-form-button">
            <button type="submit">Send</button>
          </div>
        </form>
      </div>
    </section>
  );
};

export default Contact;
