import React, { useState, useEffect, useRef } from 'react';
import './start.css';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { ScrollToPlugin } from 'gsap/ScrollToPlugin';

// 서비스 섹션 이미지 (세 번째 섹션)
import serviceImg1 from '../../../assets/concert1.jpg';
import serviceImg2 from '../../../assets/console4.png';
import serviceImg3 from '../../../assets/concert3.jpg';

// 두 번째 섹션 우측에 사용할 이미지
import incImage from '../../../assets/concert2.jpg';

// 'start-sample' 섹션의 배경 이미지를 import
import sampleBackground from '../../../assets/concert4.jpg'; // 경로는 실제 경로에 맞게 조정

gsap.registerPlugin(ScrollTrigger, ScrollToPlugin);

/* 모달 팝업 컴포넌트 */
const Modal = ({ isOpen, onClose }) => {
  return (
    <div className={`start-modal-overlay ${isOpen ? 'active' : ''}`}>
      <div className="start-modal-content">
        <div>
          <h2>More Info</h2>
          <p>죄송합니다...최대한 빨리 업데이트하겠습니다.</p>
          <button onClick={onClose}>close</button>
        </div>
      </div>
    </div>
  );
};
/* 서비스 항목 데이터 (세 번째 섹션) */
const serviceItems = [
  {
    id: 1,
    title: 'INNOVATION',
    subtitle: '혁신',
    text: '기존의 사운드 시스템을 혁신적으로 변화시키고, 새로운 경험을 제공합니다. 값비싸고 복잡한 시스템을 대체할 수 있는 혁신적인 솔루션을 제공합니다.',
    image: serviceImg1,
  },
  {
    id: 2,
    title: 'ACCESSIBILITY',
    subtitle: '접근성',
    text: '기존의 유료 시스템과 높은 금액대의 소프트웨어로 인해 접근하기 어려운 사용자들을 위해, 무료로 제공되는 소프트웨어를 통해 누구나 쉽게 사용할 수 있도록 합니다.',
    image: serviceImg2,
  },
  {
    id: 3,
    title: 'PROFESSIONALISM',
    subtitle: '전문성',
    text: '전문가들이 사용하는 고급 소프트웨어와 동일한 기능을 제공하여, 사용자가 전문적인 작업을 수행할 수 있도록 지원합니다. 또한, 사용자 피드백을 반영하여 지속적으로 개선합니다.',
    image: serviceImg3,
  },
];

const Start = () => {
  // 섹션 참조
  const secondSectionRef = useRef(null);
  const incSectionRef = useRef(null);

  // 커스텀 커서 참조
  const cursorRef = useRef(null);
  useEffect(() => {
    const handleMouseMove = (e) => {
      if (cursorRef.current) {
        cursorRef.current.style.left = `${e.clientX}px`;
        cursorRef.current.style.top = `${e.clientY}px`;
      }
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // 기존 두 번째 섹션 애니메이션 (start-sample)
  useEffect(() => {
    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: "#start-sample",
        start: "30% center",
        end: "101% bottom",
        scrub: true,
      }
    });
    tl.fromTo(
      ".start-word01",
      { width: "0%", opacity: 0 },
      { width: "auto", opacity: 1, duration: 1.2, ease: "power2.out" }
    ).fromTo(
      ".start-word02",
      { width: "0%", opacity: 0 },
      { width: "auto", opacity: 1, duration: 1.2, ease: "power2.out" },
      "-=0.8"
    );
  }, []);

  // 좌측 텍스트 효과 (inc01 섹션)
  useEffect(() => {
    const textElements = gsap.utils.toArray('#inc01 .b_txt');
    textElements.forEach(text => {
      gsap.to(text, {
        backgroundSize: '100%',
        ease: 'none',
        scrollTrigger: {
          trigger: text,
          start: 'center 110%',
          end: 'center 50%',
          scrub: true,
        },
      });
    });
  }, []);

  // 우측 이미지 fade in (inc01 섹션)
  useEffect(() => {
    gsap.fromTo(
      ".side-fade-image",
      { opacity: 0, x: 100 },
      { 
        opacity: 1, 
        x: 0,
        ease: 'power2.out',
        scrollTrigger: {
          trigger: ".side-fade-image",
          start: "top 90%",
          end: "top 60%",
          scrub: true,
        },
      }
    );
  }, []);

  // Our Service 섹션: 텍스트와 이미지 애니메이션
  useEffect(() => {
    // 1) 텍스트/아티클 페이드인
    gsap.utils.toArray('.start-service-article').forEach(article => {
      gsap.fromTo(
        article,
        { opacity: 0, y: 50 },
        {
          opacity: 1, 
          y: 0,
          duration: 1,
          ease: 'power2.out',
          scrollTrigger: {
            trigger: article,
            start: "top 80%",
            end: "bottom 60%",
            scrub: false,
          }
        }
      );
    });

    // 2) 이미지 (.service-image) 페이드인 + 확대 복원
    const serviceImgs = document.querySelectorAll('.service-image');
    serviceImgs.forEach(img => {
      gsap.fromTo(
        img,
        { opacity: 0, scale: 0.8 },
        {
          opacity: 1,
          scale: 1,
          duration: 1,
          ease: 'power2.out',
          scrollTrigger: {
            trigger: img,
            start: "top 90%",
            end: "bottom 60%",
            scrub: false,
          }
        }
      );
    });
  }, []);

  // inc02 섹션 data-count 애니메이션 (GSAP 활용)
  useEffect(() => {
    const countElems = document.querySelectorAll('.counting');
    countElems.forEach(elem => {
      const target = +elem.getAttribute('data-count');
      let obj = { val: 0 };
      gsap.to(obj, {
        val: target,
        duration: 3,
        ease: 'linear',
        onUpdate: () => {
          elem.innerText = Math.floor(obj.val);
        },
        onComplete: () => {
          elem.innerText = target;
        }
      });
    });
  }, []);

  // 모달 팝업 상태
  const [showModal, setShowModal] = useState(false);
  const openModal = () => setShowModal(true);
  const closeModal = () => setShowModal(false);

  // start-sample 배경 이미지 적용
  useEffect(() => {
    const startSample = document.getElementById("start-sample");
    if (startSample) {
      startSample.style.backgroundImage = `url(${sampleBackground})`;
    }
  }, []);

  return (
    <div className="start-container">
      {/* 커스텀 커서 */}
      <div className="start-custom-cursor" ref={cursorRef}></div>

      {/* 모달 팝업 */}
      <Modal isOpen={showModal} onClose={closeModal} />

      {/* 기존 두 번째 섹션: start-sample */}
      <article id="start-sample" className="start-sample start-scroll-section" ref={secondSectionRef}>
        <div className="start-inner txt_area">
          <p>AFX</p>
          <p className="start-txt start-word01">+ Audio Forge</p>
          <p className="start-txt start-word02">+ Experience </p>
        </div>
      </article>

      {/* 새 섹션: inc01 - 좌측 텍스트, 우측 이미지 */}
      <section id="inc01" className="start-scroll-section" ref={incSectionRef}>
        <div className="inc01-container">
          {/* 좌측 텍스트 영역 */}
          <div className="big_txt">
            <p className="b_txt">Craft Your Sound</p>
            <p className="b_txt">Find The Perfect Tool</p>
            <p className="b_txt">Experience PlugIn</p>
            <p className="b_txt">For Free</p>
          </div>
          {/* 우측 이미지 영역 */}
          <div className="inc01-image">
            <img src={incImage} alt="웹 디자인 예시" className="side-fade-image" />
          </div>
        </div>
      </section>

      {/* 새 섹션: inc02 - 정보 섹션 */}
      <article id="inc02" className="start-scroll-section">
        <div className="tit_area">
          <p>Information</p>
          <div className="pl">
            "Audio Forge Experience" (AFX)
          </div>
        </div>
        <ul>
          <li>
            <p>
              <span className="counting" data-count="45">0</span>
              <i>%</i>
            </p>
            <p className="tit">Dev Rate</p>
            <div>
              현재 다양한 서비스를 제작하기 위해 노력하고 있습니다. 음향에 도움이 되는 체계적인 서비스를 개발합니다.
            </div>
          </li>
          <li>
            <p>
              <span className="counting" data-count="5">0</span>
            </p>
            <p className="tit">Dev PlugIn</p>
            <div>
              Equalizer, Compressor, Reverb, ... 기본적이면서 심회된 플러그인과 독창적인 서비스를 제공합니다.
            </div>
          </li>
          <li>
            <p>
              <span className="counting" data-count="1">0</span>
            </p>
            <p className="tit">Dev Staff</p>
            <div>
              혼자서 개발 중입니다... "IHS"
            </div>
          </li>
        </ul>
      </article>

      {/* 세 번째 섹션: Our Service */}
      <section className="start-our-service start-scroll-section">
        <h2 className="start-service-title">AFX's Values</h2>
        {serviceItems.map((item, index) => (
          <article key={item.id} className="start-service-article">
            <figure className={`start-item ${index % 2 !== 0 ? "start-reverse" : ""}`}>
              <div className="start-cont">
                <figcaption className="start-tit">
                  {item.title}
                  <span>{item.subtitle}</span>
                </figcaption>
                <div>{item.text}</div>
                <a href="#!" onClick={openModal}>
                  <span className="material-symbols-outlined">Look More</span>
                </a>
              </div>
              <div className="start-img_box">
                <div className="start-img">
                  {item.image && (
                    <img src={item.image} alt={item.title} className="service-image" />
                  )}
                </div>
              </div>
            </figure>
          </article>
        ))}
      </section>

      {/* 네 번째 섹션 (푸터) */}
      <footer className="start-footer-section start-scroll-section">
        <div className="footer-top">
          {/* 로고 이미지 2개를 나란히 배치 */}
          {/* 상단 메뉴 */}
          <nav className="footer-nav">
            <ul>
              <li><a href="#">Information</a></li>
              <li><a href="/contact">Contact</a></li>
              <li><a href="service">Service</a></li>
              <li><a href="https://www.instagram.com/ihs0926?igsh=bTBlcDFpOWJ0dmk1">instagram</a></li>
            </ul>
          </nav>
        </div>

        <div className="footer-middle">
          <div className="footer-left-info">
            <p>상호명: AFX (Audio Forge Experience)</p>
            <p>이메일: him21176@gmail.com</p>
            <p>개발자: IHS</p>
          </div>
          <div className="footer-right-info">
            <p>No Office Building For AFX</p>
            <p>2024 ~ Future</p>
          </div>
        </div>

        <div className="footer-bottom">
          <div className="footer-bottom-left">
            <p>© AFX site. All right reserved.</p>
          </div>
          <div className="footer-bottom-right">
          </div>
        </div>
      </footer>
    </div>
  );
};

export default Start;
