import React, { useState, useEffect, useRef } from "react";
import "./dsr.css";

const DEFAULTS = {
  volume: 0.5,
  pan: 0,
  deesserLevel: 0.5,
  threshold: -20,
  gainControl: -10,
  deesserFrequency: 4000,
};

const DSR = () => {
  const [audioSource, setAudioSource] = useState("microphone");
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioContext, setAudioContext] = useState(null);
  const [analyser, setAnalyser] = useState(null);
  const [gainNode, setGainNode] = useState(null);
  const [panNode, setPanNode] = useState(null);
  const [volume, setVolume] = useState(DEFAULTS.volume); // 0.0 ~ 1.0
  const [pan, setPan] = useState(DEFAULTS.pan); // -1 (왼쪽) ~ 1 (오른쪽)
  const [audioElement, setAudioElement] = useState(null);
  const [audioFileLoaded, setAudioFileLoaded] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [deviceList, setDeviceList] = useState({ microphone: null, usb: null });
  const [mediaStream, setMediaStream] = useState(null);

  // de-esser 관련 state
  const [deesserLevel, setDeesserLevel] = useState(DEFAULTS.deesserLevel);
  const [threshold, setThreshold] = useState(DEFAULTS.threshold);
  const [gainControl, setGainControl] = useState(DEFAULTS.gainControl);
  const [deesserFrequency, setDeesserFrequency] = useState(DEFAULTS.deesserFrequency);

  // de-esser 오디오 노드
  const [deesserFilter, setDeesserFilter] = useState(null);
  const [deesserGainNode, setDeesserGainNode] = useState(null);
  const [deesserCompressor, setDeesserCompressor] = useState(null);

  const analyserCanvas = useRef(null);
  const fileInputRef = useRef(null);
  const mediaStreamSource = useRef(null);
  const fileSourceRef = useRef(null); // 파일 소스 노드를 한 번만 생성하기 위해
  const animationFrameRef = useRef(null);

  // 장치 목록 (노트북 마이크, USB) 얻기
  useEffect(() => {
    navigator.mediaDevices.enumerateDevices().then((devices) => {
      const audioInputs = devices.filter((d) => d.kind === "audioinput");
      setDeviceList({
        microphone: audioInputs[0]?.deviceId || null,
        usb: audioInputs[1]?.deviceId || audioInputs[0]?.deviceId || null,
      });
    });
  }, []);

  // AudioContext와 기본 노드 및 de-esser 노드 생성
  const initializeAudioContext = (source) => {
    const AudioContext = window.AudioContext || window.webkitAudioContext;
    const newAudioContext = new AudioContext();
    setAudioContext(newAudioContext);

    // analyser 설정 (fftSize를 2048로 설정하여 해상도 향상)
    const newAnalyser = newAudioContext.createAnalyser();
    newAnalyser.fftSize = 2048; // frequencyBinCount = 1024
    setAnalyser(newAnalyser);

    // de-esser 관련 노드 생성
    const newDeesserFilter = newAudioContext.createBiquadFilter();
    newDeesserFilter.type = "peaking";
    newDeesserFilter.frequency.value = deesserFrequency;
    newDeesserFilter.gain.value = gainControl;
    newDeesserFilter.Q.value = 1;
    setDeesserFilter(newDeesserFilter);

    const newDeesserGainNode = newAudioContext.createGain();
    newDeesserGainNode.gain.value = deesserLevel;
    setDeesserGainNode(newDeesserGainNode);

    const newDeesserCompressor = newAudioContext.createDynamicsCompressor();
    newDeesserCompressor.threshold.value = threshold;
    // compressor의 다른 파라미터는 필요에 따라 조정 가능
    setDeesserCompressor(newDeesserCompressor);

    // Gain 노드 설정
    const newGainNode = newAudioContext.createGain();
    newGainNode.gain.value = volume;
    setGainNode(newGainNode);

    // Pan 노드 설정
    const newPanNode = newAudioContext.createStereoPanner();
    newPanNode.pan.value = pan;
    setPanNode(newPanNode);

    // 오디오 체인 구성: de-esser 체인을 gain -> pan -> destination 전에 삽입
    // 체인: source -> analyser -> deesserFilter -> deesserGainNode -> deesserCompressor -> gainNode -> panNode -> destination
    newGainNode.connect(newPanNode);
    newPanNode.connect(newAudioContext.destination);
  };

  // file 소스 연결 시 de-esser 체인을 반영하여 연결
  useEffect(() => {
    if (audioSource === "file" && audioElement && audioContext && analyser && gainNode && deesserFilter && deesserGainNode && deesserCompressor) {
      if (!fileSourceRef.current) {
        fileSourceRef.current = audioContext.createMediaElementSource(audioElement);
        fileSourceRef.current.connect(analyser);
        analyser.connect(deesserFilter);
        deesserFilter.connect(deesserGainNode);
        deesserGainNode.connect(deesserCompressor);
        deesserCompressor.connect(gainNode);
      }
    }
  }, [audioSource, audioElement, audioContext, analyser, gainNode, deesserFilter, deesserGainNode, deesserCompressor]);

  // 볼륨 상태 변경시 gainNode 업데이트
  useEffect(() => {
    if (gainNode) gainNode.gain.value = volume;
  }, [volume, gainNode]);

  // 패닝 상태 변경시 panNode 업데이트
  useEffect(() => {
    if (panNode) panNode.pan.value = pan;
  }, [pan, panNode]);

  // de-esser 관련 state 업데이트시 해당 노드 업데이트
  useEffect(() => {
    if (deesserFilter) {
      deesserFilter.frequency.value = deesserFrequency;
      deesserFilter.gain.value = gainControl;
    }
  }, [deesserFrequency, gainControl, deesserFilter]);

  useEffect(() => {
    if (deesserGainNode) {
      deesserGainNode.gain.value = deesserLevel;
    }
  }, [deesserLevel, deesserGainNode]);

  useEffect(() => {
    if (deesserCompressor) {
      deesserCompressor.threshold.value = threshold;
    }
  }, [threshold, deesserCompressor]);

  // 소스 변경 시 기존 스트림, 파일, AudioContext 정리 후 재초기화
  const handleSourceChange = (e) => {
    const newSource = e.target.value;
    setAudioSource(newSource);

    if (mediaStream) {
      mediaStream.getTracks().forEach((track) => track.stop());
      setMediaStream(null);
    }
    if (audioElement) {
      audioElement.pause();
      setAudioElement(null);
      setAudioFileLoaded(false);
      fileSourceRef.current = null;
    }
    if (audioContext) {
      audioContext.close();
    }
    initializeAudioContext(newSource);
    setIsPlaying(false);
  };

  // play 버튼 클릭 시 AudioContext resume 및 소스 연결
  const handlePlay = () => {
    if (!audioContext) return;
    if (audioContext.state === "suspended") {
      audioContext.resume();
    }

    if (audioSource === "file") {
      if (audioElement) {
        audioElement.play();
        setIsPlaying(true);
      }
    } else {
      if (mediaStream) {
        setIsPlaying(true);
        return;
      }
      const selectedDeviceId =
        audioSource === "usb" ? deviceList.usb : deviceList.microphone;
      const constraints = selectedDeviceId
        ? { audio: { deviceId: { exact: selectedDeviceId } } }
        : { audio: true };

      navigator.mediaDevices
        .getUserMedia(constraints)
        .then((stream) => {
          setMediaStream(stream);
          mediaStreamSource.current = audioContext.createMediaStreamSource(stream);
          mediaStreamSource.current.connect(analyser);
          analyser.connect(deesserFilter);
          deesserFilter.connect(deesserGainNode);
          deesserGainNode.connect(deesserCompressor);
          deesserCompressor.connect(gainNode);
          setIsPlaying(true);
        })
        .catch((err) => console.error("getUserMedia error:", err));
    }
  };

  // stop 버튼 클릭 시 소스 정지 처리
  const handleStop = () => {
    if (audioSource === "file" && audioElement) {
      audioElement.pause();
      setIsPlaying(false);
    } else if (mediaStream) {
      mediaStream.getTracks().forEach((track) => track.stop());
      setMediaStream(null);
      setIsPlaying(false);
    }
  };

  // requestAnimationFrame을 이용한 실시간 주파수 그래프 업데이트
  const updateAndDraw = () => {
    if (analyser && analyserCanvas.current) {
      const bufferLength = analyser.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      analyser.getByteFrequencyData(dataArray);

      const canvas = analyserCanvas.current;
      const ctx = canvas.getContext("2d");
      const width = canvas.width;
      const height = canvas.height;
      ctx.clearRect(0, 0, width, height);

      // 막대그래프 그리기 (0~20000 Hz 스케일)
      const barWidth = width / bufferLength;
      for (let i = 0; i < bufferLength; i++) {
        const barHeight = dataArray[i];
        // x 위치: (현재 bin이 나타내는 주파수 / 20000) * 전체 width
        const x = (i / bufferLength) * width;
        ctx.fillStyle = `#000(${barHeight + 100},50,50)`;
        ctx.fillRect(x, height - barHeight, barWidth - 1, barHeight);
      }

      // X축 레이블: 레이블의 위치를 (label/20000)*width로 계산
      const frequencyLabels = [20, 40, 60, 100, 200, 400, 600, 1000, 2000, 3000, 4000, 5000, 6000, 10000, 20000];
      frequencyLabels.forEach((label) => {
        const labelX = (label / 20000) * width;
        ctx.fillStyle = "#000";
        ctx.fillText(label + "Hz", labelX, height - 10);
      });

      // Y축 레이블 (예시)
      const yLabels = [0, 5, 10, 15];
      const labelHeight = height / yLabels.length;
      yLabels.forEach((label, index) => {
        const labelY = height - (index * labelHeight);
        ctx.fillStyle = "#000";
        ctx.fillText(label + " dB", 0, labelY);
      });
    }
    animationFrameRef.current = requestAnimationFrame(updateAndDraw);
  };

  useEffect(() => {
    animationFrameRef.current = requestAnimationFrame(updateAndDraw);
    return () => cancelAnimationFrame(animationFrameRef.current);
  }, [analyser]);

  // 컨트롤러 onChange 및 onBlur 핸들러 (빈 문자열이면 기본값 복원)
  const handleVolumeChange = (e) => {
    const newVal = e.target.value;
    if (newVal === "") return;
    setVolume(parseFloat(newVal));
  };

  const handlePanChange = (e) => {
    const newVal = e.target.value;
    if (newVal === "") return;
    setPan(parseFloat(newVal));
  };

  const handleDeesserLevelChange = (e) => {
    const newVal = e.target.value;
    if (newVal === "") return;
    setDeesserLevel(parseFloat(newVal));
  };

  const handleThresholdChange = (e) => {
    const newVal = e.target.value;
    if (newVal === "") return;
    setThreshold(parseFloat(newVal));
  };

  const handleGainControlChange = (e) => {
    const newVal = e.target.value;
    if (newVal === "") return;
    setGainControl(parseFloat(newVal));
  };

  const handleDeesserFrequencyChange = (e) => {
    const newVal = e.target.value;
    if (newVal === "") return;
    setDeesserFrequency(parseFloat(newVal));
  };

  // onBlur 핸들러: 빈 문자열이면 기본값 복원
  const handleBlur = (e, defaultValue, setter) => {
    if (e.target.value === "") {
      setter(defaultValue);
    }
  };

  // 파일 선택 핸들러
  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && audioContext) {
      const newAudioElement = new Audio(URL.createObjectURL(file));
      setAudioElement(newAudioElement);
      newAudioElement.addEventListener("canplaythrough", () => {
        setAudioFileLoaded(true);
        setDuration(newAudioElement.duration);
      });
    }
  };

  // 파일 타임라인 변경 핸들러
  const handleTimeChange = (e) => {
    if (audioElement) {
      const newTime = parseFloat(e.target.value);
      audioElement.currentTime = newTime;
      setCurrentTime(newTime);
    }
  };

  // 오디오 파일 재생 중 현재 시간 업데이트
  useEffect(() => {
    let interval;
    if (audioElement && isPlaying) {
      interval = setInterval(() => {
        setCurrentTime(audioElement.currentTime);
      }, 100);
    }
    return () => clearInterval(interval);
  }, [isPlaying, audioElement]);

  return (
    <div className="dsr-container">
      <h1>De-esser Control</h1>
      <select onChange={handleSourceChange} value={audioSource} className="dsr-source-selector">
        <option value="microphone">노트북 마이크</option>
        <option value="usb">USB 오디오 인터페이스</option>
        <option value="file">오디오 파일</option>
      </select>
      <div className="dsr-audio-controls">
        <button onClick={handlePlay} disabled={isPlaying || (audioSource === "file" && !audioFileLoaded)}>
          Play
        </button>
        <button onClick={handleStop} disabled={!isPlaying}>
          Stop
        </button>
      </div>
      {audioSource === "file" && (
        <div className="dsr-file-input">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="audio/mp3, audio/wav" />
        </div>
      )}
      {audioSource === "file" && audioFileLoaded && (
        <div className="dsr-timeline">
          <input
            type="range"
            min="0"
            max={duration}
            step="0.01"
            value={currentTime}
            onChange={handleTimeChange}
            className="dsr-timeline-slider"
          />
          <div className="dsr-time-display">
            {Math.floor(currentTime / 60)}:{Math.floor(currentTime % 60)} / {Math.floor(duration / 60)}:{Math.floor(duration % 60)}
          </div>
        </div>
      )}

      {/* 컨트롤러 그룹: Volume & Pan */}
      <div className="dsr-faders-group">
        <div className="dsr-fader">
          <label>Volume</label>
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={volume}
            onChange={handleVolumeChange}
          />
          <input
            type="number"
            min="0"
            max="1"
            step="0.01"
            value={volume}
            onChange={handleVolumeChange}
            onBlur={(e) => handleBlur(e, DEFAULTS.volume, setVolume)}
            className="dsr-fader-input"
          />
        </div>
        <div className="dsr-fader">
          <label>Pan</label>
          <input
            type="range"
            min="-1"
            max="1"
            step="0.01"
            value={pan}
            onChange={handlePanChange}
          />
          <input
            type="number"
            min="-1"
            max="1"
            step="0.01"
            value={pan}
            onChange={handlePanChange}
            onBlur={(e) => handleBlur(e, DEFAULTS.pan, setPan)}
            className="dsr-fader-input"
          />
        </div>
      </div>

      {/* 컨트롤러 그룹: De-esser Controls */}
      <div className="dsr-faders-group">
        <div className="dsr-fader">
          <label>De-esser Level</label>
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={deesserLevel}
            onChange={handleDeesserLevelChange}
          />
          <input
            type="number"
            min="0"
            max="1"
            step="0.01"
            value={deesserLevel}
            onChange={handleDeesserLevelChange}
            onBlur={(e) => handleBlur(e, DEFAULTS.deesserLevel, setDeesserLevel)}
            className="dsr-fader-input"
          />
        </div>
        <div className="dsr-fader">
          <label>Threshold (dB)</label>
          <input
            type="range"
            min="-60"
            max="0"
            step="1"
            value={threshold}
            onChange={handleThresholdChange}
          />
          <input
            type="number"
            min="-60"
            max="0"
            step="1"
            value={threshold}
            onChange={handleThresholdChange}
            onBlur={(e) => handleBlur(e, DEFAULTS.threshold, setThreshold)}
            className="dsr-fader-input"
          />
        </div>
        <div className="dsr-fader">
          <label>Gain Control (dB)</label>
          <input
            type="range"
            min="-30"
            max="30"
            step="1"
            value={gainControl}
            onChange={handleGainControlChange}
          />
          <input
            type="number"
            min="-30"
            max="30"
            step="1"
            value={gainControl}
            onChange={handleGainControlChange}
            onBlur={(e) => handleBlur(e, DEFAULTS.gainControl, setGainControl)}
            className="dsr-fader-input"
          />
        </div>
        <div className="dsr-fader">
          <label>De-esser Frequency (Hz)</label>
          <input
            type="range"
            min="1000"
            max="10000"
            step="100"
            value={deesserFrequency}
            onChange={handleDeesserFrequencyChange}
          />
          <input
            type="number"
            min="1000"
            max="10000"
            step="100"
            value={deesserFrequency}
            onChange={handleDeesserFrequencyChange}
            onBlur={(e) => handleBlur(e, DEFAULTS.deesserFrequency, setDeesserFrequency)}
            className="dsr-fader-input"
          />
        </div>
      </div>
      <canvas ref={analyserCanvas} width="1000" height="300" className="dsr-frequency-graph"></canvas>
    </div>
  );
};

export default DSR;
