import React, { useState } from 'react';
import './chat.css';
import aiIcon from '../../../assets/chat2.png'; // 아이콘 경로는 실제 프로젝트 구조에 맞게 조정

function Chat() {
  const [input, setInput] = useState('');
  const [conversation, setConversation] = useState([]); // { sender: 'user' 또는 'ai', text: 메시지 }
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage = { sender: 'user', text: input };
    setConversation((prev) => [...prev, userMessage]);
    setLoading(true);

    try {
      const response = await fetch(
        'https://comicman.app.n8n.cloud/webhook/aad527d8-98e9-42ac-a34b-bb2019c77acd',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({ message: input })
        }
      );

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`HTTP error! status: ${response.status} - ${errorText}`);
      }
      
      const data = await response.json();
      console.log("받은 응답 데이터:", data);
      const replyText = Array.isArray(data) && data.length > 0 ? data[0].output : data.reply;
      // "알겠습니다." 또는 "알겠습니다"가 앞에 붙었으면 제거 (공백 포함)
      const cleanedReply = replyText.replace(/^알겠습니다\.?\s*/, '');
      const aiMessage = {
        sender: 'ai',
        text: cleanedReply || '응답을 받지 못하였습니다.'
      };
      setConversation((prev) => [...prev, aiMessage]);
    } catch (error) {
      console.error("메시지 전송 중 오류 발생:", error);
      const errorMessage = { sender: 'ai', text: '요청 처리 중 오류가 발생했습니다.' };
      setConversation((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
      setInput('');
    }
  };

  const handleReset = () => {
    setConversation([]);
  };

  const toggleModal = () => {
    setModalOpen((prev) => !prev);
  };

  return (
    <>
      {/* 채팅 아이콘 버튼: 아래 버튼은 마우스 오버 시 확대되고 텍스트가 나타나는 애니메이션 효과가 적용됨 */}
      <button className="chat-btn" onClick={toggleModal}>
        <div className="sign">
          <img src={aiIcon} alt="Chat Icon" />
        </div>
        <div className="text">Help</div>
      </button>

      {/* 모달 형식의 채팅창: 채팅 아이콘에서 확대 및 페이드인 효과로 나타남 */}
      {modalOpen && (
        <div className="chat-modal" onClick={toggleModal}>
          <div className="chat-modal-content" onClick={(e) => e.stopPropagation()}>
            {/* 헤더 영역: Uiverse 스타일 적용 */}
            <header className="chat-card-header">
              <div className="circles">
                <div className="c"></div>
                <div className="c"></div>
                <div className="c"></div>
              </div>
              <div className="browser">
                <div className="chevrons">
                  <svg
                    viewBox="0 0 20 20"
                    height="16"
                    width="16"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      transform="translate(6.25 3.75)"
                      d="M0,6.25,6.25,0l.875.875L1.75,6.25l5.375,5.375L6.25,12.5Z"
                      fill="white"
                    ></path>
                  </svg>
                  <svg
                    viewBox="0 0 20 20"
                    height="16"
                    width="16"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      transform="translate(6.625 3.75)"
                      d="M7.125,6.25.875,12.5,0,11.625,5.375,6.25,0,.875.875,0Z"
                      fill="white"
                    ></path>
                  </svg>
                </div>
                <div className="search-bar">
                  AFX-Chat AI
                </div>
                <button className="chat-reset-button" onClick={handleReset}>reset</button>
              </div>
            </header>
            {/* 채팅 내역과 입력 영역 */}
            <div className="chat-container">
              <div className="chat-window">
                {conversation.map((msg, index) => (
                  <div key={index} className={`chat-message ${msg.sender}`}>
                    {msg.text}
                  </div>
                ))}
                {loading && <div className="chat-message ai">질문에 대한 답변을 생각 중...</div>}
              </div>
              <form className="chat-input-form" onSubmit={handleSubmit}>
                <input
                  type="text"
                  className="chat-input"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  placeholder="Sound 관련 질문을 입력하세요."
                />
                <button type="submit" className="chat-submit-button" disabled={loading}>
                  send
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

export default Chat;
